package com.example.commentapp.model;

import java.time.LocalDateTime;

public class Comment {
    private Long id;
    private String author;
    private String content;
    private LocalDateTime postDate;

    public Comment() {
    }

    public Comment(Long id, String author, String content, LocalDateTime postDate) {
        this.id = id;
        this.author = author;
        this.content = content;
        this.postDate = postDate;
    }

    // Getters and Setters
    public Long getId() {
        return id;
    }

    public void setId(Long id) {
        this.id = id;
    }

    public String getAuthor() {
        return author;
    }

    public void setAuthor(String author) {
        this.author = author;
    }

    public String getContent() {
        return content;
    }

    public void setContent(String content) {
        this.content = content;
    }

    public LocalDateTime getPostDate() {
        return postDate;
    }

    public void setPostDate(LocalDateTime postDate) {
        this.postDate = postDate;
    }
}

package com.example.commentapp.service;

import com.example.commentapp.model.Comment;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Service
public class CommentService {

    // In a real application, this would interact with a database
    // e.g., using Spring Data JPA Repository
    private final List<Comment> comments = new ArrayList<>();

    public CommentService() {
        // Populate with some dummy data
        comments.add(new Comment(1L, "Alice", "This is my <b>first</b> comment! It's <i>great</i>.", LocalDateTime.now().minusDays(2)));
        comments.add(new Comment(2L, "Bob", "Hello everyone! <p>I hope you're having a wonderful day.</p>", LocalDateTime.now().minusDays(1)));
        comments.add(new Comment(3L, "Charlie", "<u>Important notice:</u> Please be kind to each other.", LocalDateTime.now()));
        comments.add(new Comment(4L, "Diana", "Another comment with some <strong>strong text</strong> and a <a href='https://example.com'>link</a>.", LocalDateTime.now().plusHours(1)));
    }

    public List<Comment> getAllComments() {
        // In a real app, you might add sorting or pagination here
        return new ArrayList<>(comments); // Return a copy to prevent external modification
    }

    public void addComment(Comment comment) {
        // In a real app, generate ID from DB, save, etc.
        comment.setId((long) (comments.size() + 1));
        comment.setPostDate(LocalDateTime.now());
        comments.add(comment);
    }
}

package com.example.commentapp.controller;

import com.example.commentapp.model.Comment;
import com.example.commentapp.service.CommentService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;

import java.util.List;

@Controller
@RequestMapping("/comments")
public class CommentController {

    private final CommentService commentService;

    @Autowired
    public CommentController(CommentService commentService) {
        this.commentService = commentService;
    }

    @GetMapping
    public String listComments(Model model) {
        List<Comment> comments = commentService.getAllComments();
        model.addAttribute("comments", comments);
        return "comments"; // This will resolve to /WEB-INF/views/comments.jsp
    }
}

